// Package host is the ConnectRPC service implementation for the
// federated-meetup client surface.
//
// The handler interface (HostServiceHandler) is GENERATED by
// protoc-gen-connect-go from proto/federated_meetup/v1/rpc.proto.
// This file is the only place domain code touches protobuf types —
// every method body is a thin bridge that:
//   1. Decodes the request (a few bytes → domain types).
//   2. Calls into internal/group, internal/types.
//   3. Encodes the response (domain types → a few bytes).
//
// No handler boilerplate is hand-written. To add or change a method:
//   - Edit rpc.proto (or the Speckl .speckdl, which regenerates the .proto).
//   - Run `scripts/proto.sh` (buf generate).
//   - Update the method body here to match the new request/response shape.
//
// SPDX-License-Identifier: AGPL-3.0
package host

import (
	"context"
	"fmt"
	"log"
	"time"

	"connectrpc.com/connect"

	"google.golang.org/protobuf/proto"

	pb "github.com/sscoble/federated-meetup/proto/federated_meetup/v1"
	"github.com/sscoble/federated-meetup/proto/federated_meetup/v1/federatedmeetupv1connect"

	"github.com/sscoble/federated-meetup/internal/group"
	"github.com/sscoble/federated-meetup/internal/types"
)

// Service implements federatedmeetupv1connect.HostServiceHandler.
//
// The host runs multiple groups; each request is routed to the right
// *group.State via the MultiGroup registry. At v0 the registry is
// populated at construction time; future cycles will populate it
// dynamically (gossip, peer sync, on-disk persistence).
type Service struct {
	// groups is the host's "which groups am I currently serving" registry.
	groups *MultiGroup
	// name is the canonical name this host uses to advertise itself in
	// ResolveName responses.
	name string
	// now is overridable for tests. Defaults to time.Now in NewService.
	now func() time.Time
}

// Compile-time assertion: Service satisfies the generated handler interface.
var _ federatedmeetupv1connect.HostServiceHandler = (*Service)(nil)

// NewService constructs a Service bound to a MultiGroup registry.
//
// name is the host's canonical name (used in ResolveName responses).
// states are the *group.State instances this host serves (one per
// group). Each state machine's GroupID() is the registry key; a
// nil entry is silently skipped.
//
// For backward compatibility with the single-group v0 callers, you
// can also construct a Service via NewServiceSingle, which wraps a
// single state in a one-entry MultiGroup.
func NewService(name string, states ...*group.State) *Service {
	return &Service{
		groups: NewMultiGroup(name, states...),
		name:   name,
		now:    time.Now,
	}
}

// NewServiceSingle is a convenience constructor for the single-group
// case. Equivalent to NewService(name, state).
func NewServiceSingle(state *group.State, name string) *Service {
	return NewService(name, state)
}

// SetClock overrides the time source. Test-only.
func (s *Service) SetClock(now func() time.Time) { s.now = now }

// Groups returns the underlying MultiGroup registry. Read-only access
// for tests; production callers should go through the service methods.
func (s *Service) Groups() *MultiGroup { return s.groups }

// ----- Reads ---------------------------------------------------------------

// GetGroup returns the current state snapshot for a group.
//
// Identifier is one of: PublicKey (preferred) or CanonicalName (resolved
// locally for v0 — future cycles may delegate to a directory host).
func (s *Service) GetGroup(
	ctx context.Context,
	req *connect.Request[pb.GetGroupRequest],
) (*connect.Response[pb.GetGroupResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	var groupKey types.PublicKey
	switch id := r.Identifier.(type) {
	case *pb.GetGroupRequest_GroupKey:
		if id.GroupKey == nil {
			return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
		}
		groupKey = bytesToKey(id.GroupKey.Raw)
	case *pb.GetGroupRequest_CanonicalName:
		// v0: no name directory yet. Reject so clients learn to use GroupKey.
		return nil, connect.NewError(connect.CodeUnimplemented, fmt.Errorf("canonical_name resolution not wired in v0; use group_key"))
	default:
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("missing identifier"))
	}
	state, err := s.lookup(groupKey)
	if err != nil {
		return nil, err
	}
	resp := &pb.GetGroupResponse{
		Snapshot:  stateSnapshotToProto(state.Snapshot(), state.Root()),
		Stewards:  stewardsToProto(state.Stewards()),
		Threshold: state.Threshold(),
	}
	return connect.NewResponse(resp), nil
}

// GetEvent returns a single event by (group, event_id).
func (s *Service) GetEvent(
	ctx context.Context,
	req *connect.Request[pb.GetEventRequest],
) (*connect.Response[pb.GetEventResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	if r.EventId == "" {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("event_id is empty"))
	}
	state, err := s.lookup(bytesToKey(r.GroupKey.Raw))
	if err != nil {
		return nil, err
	}
	// Walk the log looking for CREATE_EVENT with matching event_id.
	for _, t := range state.Log() {
		if t == nil || t.Proto == nil {
			continue
		}
		if t.Type() != pb.TransitionType_TRANSITION_TYPE_CREATE_EVENT {
			continue
		}
		p := t.Proto.GetCreateEvent()
		if p != nil && p.EventId == r.EventId {
			return connect.NewResponse(&pb.GetEventResponse{
				Event:     p,
				Rsvps:     nil,
				Cancelled: false,
			}), nil
		}
	}
	return nil, connect.NewError(connect.CodeNotFound, fmt.Errorf("event %q not found", r.EventId))
}

// ListEvents pages through a group's event log.
func (s *Service) ListEvents(
	ctx context.Context,
	req *connect.Request[pb.ListEventsRequest],
) (*connect.Response[pb.ListEventsResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	state, err := s.lookup(bytesToKey(r.GroupKey.Raw))
	if err != nil {
		return nil, err
	}

	pageSize := int(r.PageSize)
	if pageSize <= 0 || pageSize > 200 {
		pageSize = 50
	}

	startIdx := uint64(0)
	if r.Cursor != "" {
		if _, err := fmt.Sscan(r.Cursor, &startIdx); err != nil {
			return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("bad cursor: %w", err))
		}
	}

	log := state.Log()
	endIdx := uint64(len(log))
	if r.Cursor != "" {
		if startIdx > endIdx {
			startIdx = endIdx
		}
		endIdx = endIdx - startIdx
	}

	events := make([]*pb.CreateEventPayload, 0, pageSize)
	nextCursor := ""
	for i := endIdx; i > 0 && len(events) < pageSize; i-- {
		t := log[i-1]
		if t == nil || t.Proto == nil {
			continue
		}
		if t.Type() != pb.TransitionType_TRANSITION_TYPE_CREATE_EVENT {
			continue
		}
		if p := t.Proto.GetCreateEvent(); p != nil {
			events = append(events, p)
		}
	}
	if uint64(len(log)) > 0 && len(events) == pageSize {
		nextCursor = fmt.Sprintf("%d", len(log))
	}
	return connect.NewResponse(&pb.ListEventsResponse{
		Events:     events,
		NextCursor: nextCursor,
	}), nil
}

// ListGroups lists all groups hosted by this host.
func (s *Service) ListGroups(
	ctx context.Context,
	req *connect.Request[pb.ListGroupsRequest],
) (*connect.Response[pb.ListGroupsResponse], error) {
	_ = req
	gids := s.groups.All()
	summaries := make([]*pb.ListGroupsResponse_GroupSummary, 0, len(gids))
	for _, gid := range gids {
		summaries = append(summaries, &pb.ListGroupsResponse_GroupSummary{
			GroupKey: keyToProto(gid),
		})
	}
	return connect.NewResponse(&pb.ListGroupsResponse{
		Groups:     summaries,
		NextCursor: "",
	}), nil
}

// ----- Writes --------------------------------------------------------------

// SubmitTransition applies a steward-signed transition to a group's
// state machine. The transition is verified against the current state
// by internal/group: cosigner signatures, multisig threshold,
// equivocation, and state invariants.
func (s *Service) SubmitTransition(
	ctx context.Context,
	req *connect.Request[pb.SubmitTransitionRequest],
) (*connect.Response[pb.SubmitTransitionResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	if r.Transition == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("transition is nil"))
	}
	groupKey := bytesToKey(r.GroupKey.Raw)
	state, err := s.lookup(groupKey)
	if err != nil {
		return nil, err
	}
	t, err := group.NewTransition(r.Transition, groupKey)
	if err != nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("invalid transition: %w", err))
	}
	idx := state.TransitionCount()
	if err := state.Apply(t, s.now()); err != nil {
		return nil, connect.NewError(connect.CodeFailedPrecondition, fmt.Errorf("apply: %w", err))
	}
	return connect.NewResponse(&pb.SubmitTransitionResponse{
		NewSnapshot:     stateSnapshotToProto(state.Snapshot(), state.Root()),
		TransitionIndex: idx,
	}), nil
}

// SubmitUserAction applies a user-signed action (RSVP, ATTEST, CANCEL_RSVP).
// The user signs the transition with their Ed25519 keypair and submits
// it via this RPC. The host applies the transition to the group state.
// Signature verification on the user envelope is deferred (v0) — the
// protocol-level Apply validates structure.
func (s *Service) SubmitUserAction(
	ctx context.Context,
	req *connect.Request[pb.SubmitUserActionRequest],
) (*connect.Response[pb.SubmitUserActionResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	if len(r.TransitionPayload) == 0 {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("transition_payload is empty"))
	}

	// Validate transition type is a user-action type.
	switch r.Type {
	case pb.TransitionType_TRANSITION_TYPE_RSVP,
		pb.TransitionType_TRANSITION_TYPE_CANCEL_RSVP,
		pb.TransitionType_TRANSITION_TYPE_ATTEST:
		// allowed
	default:
		return nil, connect.NewError(connect.CodeInvalidArgument,
			fmt.Errorf("type %s is not a valid user action", r.Type))
	}

	// v0: skip signature verification on the user envelope.
	if r.UserEnvelope != nil {
		log.Printf("WARN: SubmitUserAction: user envelope signature verification skipped (v0)")
	}

	groupKey := bytesToKey(r.GroupKey.Raw)
	state, err := s.lookup(groupKey)
	if err != nil {
		return nil, err
	}

	// Unmarshal the transition payload.
	var trProto pb.Transition
	if err := proto.Unmarshal(r.TransitionPayload, &trProto); err != nil {
		return nil, connect.NewError(connect.CodeInvalidArgument,
			fmt.Errorf("invalid transition payload: %w", err))
	}

	// Validate the unmarshaled transition's type matches the request.
	if trProto.Type != r.Type {
		return nil, connect.NewError(connect.CodeInvalidArgument,
			fmt.Errorf("transition type %s does not match request type %s", trProto.Type, r.Type))
	}

	// Stamp PriorState with current root if not already set.
	if trProto.PriorState == nil {
		root := state.Root()
		trProto.PriorState = &pb.StateRoot{Hash: root[:]}
	}

	// Construct the domain Transition and apply.
	t, err := group.NewTransition(&trProto, groupKey)
	if err != nil {
		return nil, connect.NewError(connect.CodeInvalidArgument,
			fmt.Errorf("invalid transition: %w", err))
	}

	if err := state.Apply(t, s.now()); err != nil {
		return nil, connect.NewError(connect.CodeFailedPrecondition,
			fmt.Errorf("apply: %w", err))
	}

	return connect.NewResponse(&pb.SubmitUserActionResponse{
		NewSnapshot: stateSnapshotToProto(state.Snapshot(), state.Root()),
	}), nil
}

// ResolveName resolves a canonical name to the group key + hosting URLs.
//
// v0: returns the FIRST hosted group + this host's name. A future cycle
// will add a name directory and a real name → GroupID mapping.
func (s *Service) ResolveName(
	ctx context.Context,
	req *connect.Request[pb.ResolveNameRequest],
) (*connect.Response[pb.ResolveNameResponse], error) {
	r := req.Msg
	if r == nil || r.CanonicalName == "" {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("canonical_name is empty"))
	}

	// Try the name directory first.
	if gid, ok := s.groups.LookupName(r.CanonicalName); ok {
		hosts := []string{}
		if s.name != "" {
			hosts = append(hosts, s.name)
		}
		return connect.NewResponse(&pb.ResolveNameResponse{
			GroupKey: keyToProto(gid),
			Hosts:    hosts,
		}), nil
	}

	// Fallback: if no name directory match, return the first hosted
	// group (v0 backward compatibility for single-group hosts).
	gids := s.groups.All()
	if len(gids) == 0 {
		return nil, connect.NewError(connect.CodeNotFound, fmt.Errorf("name %q not found and no groups hosted here", r.CanonicalName))
	}
	hosts := []string{}
	if s.name != "" {
		hosts = append(hosts, s.name)
	}
	return connect.NewResponse(&pb.ResolveNameResponse{
		GroupKey: keyToProto(gids[0]),
		Hosts:    hosts,
	}), nil
}

// ----- Internal helpers ----------------------------------------------------

// GetLog returns a paginated slice of the group's transition log.
// Mirrors bootstrap from history by walking the log from since_cursor.
//
// (Audit H-7, cycle 51.)
func (s *Service) GetLog(
	ctx context.Context,
	req *connect.Request[pb.GetLogRequest],
) (*connect.Response[pb.GetLogResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	groupKey := bytesToKey(r.GroupKey.Raw)
	state, err := s.lookup(groupKey)
	if err != nil {
		return nil, err
	}

	log := state.Log()
	total := uint64(len(log))
	since := r.GetSinceCursor()
	limit := r.GetLimit()
	if limit == 0 {
		limit = 100
	}
	// Server-side cap to avoid huge responses.
	if limit > 1000 {
		limit = 1000
	}

	start := since
	if start > total {
		start = total
	}
	end := start + uint64(limit)
	if end > total {
		end = total
	}

	var transitions []*pb.Transition
	if start < end {
		for i := start; i < end; i++ {
			transitions = append(transitions, log[i].Proto)
		}
	}

	nextCursor := uint64(0)
	if end < total {
		nextCursor = end
	}

	return connect.NewResponse(&pb.GetLogResponse{
		Transitions: transitions,
		NextCursor:  nextCursor,
		Total:       total,
	}), nil
}

// GetSnapshot returns the current state snapshot (or a snapshot at a
// specific root if requested). Mirrors use this to bootstrap their
// local copy without replaying the entire log.
//
// (Audit H-8, cycle 51.)
func (s *Service) GetSnapshot(
	ctx context.Context,
	req *connect.Request[pb.GetSnapshotRequest],
) (*connect.Response[pb.GetSnapshotResponse], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	groupKey := bytesToKey(r.GroupKey.Raw)
	state, err := s.lookup(groupKey)
	if err != nil {
		return nil, err
	}

	// v0: only current-head snapshots. Root-keyed lookups are a future
	// cycle (requires a root → snapshot index, which is the snapshot store
	// from the branch registry). If root is specified, return Unimplemented.
	if r.Root != nil {
		return nil, connect.NewError(connect.CodeUnimplemented,
			fmt.Errorf("snapshot-by-root not implemented in v0 (use nil root for current head)"))
	}

	snap := state.Snapshot()
	root := state.Root()
	count := state.TransitionCount()

	return connect.NewResponse(&pb.GetSnapshotResponse{
		Snapshot:         stateSnapshotToProto(snap, root),
		TransitionIndex:  count,
	}), nil
}

// SubmitEvidence receives equivocation evidence from a peer host.
// The host stores it for SLASH_STEWARD submission and returns an Ack.
//
// v0: stores the evidence in the state's evidence list. Does not
// auto-submit SLASH_STEWARD — that's a future cycle (requires the
// host to hold steward keys to sign the slash transition).
//
// (Audit H-9, cycle 51.)
func (s *Service) SubmitEvidence(
	ctx context.Context,
	req *connect.Request[pb.EvidenceEnvelope],
) (*connect.Response[pb.Ack], error) {
	r := req.Msg
	if r == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	groupKey := bytesToKey(r.GroupKey.Raw)
	state, err := s.lookup(groupKey)
	if err != nil {
		return nil, err
	}

	// Store the evidence. The group package's EquivocationEvidence
	// is the internal type; we convert from the proto envelope.
	var stewardKey types.PublicKey
	copy(stewardKey[:], r.GetStewardKey().GetRaw())
	var priorState types.Hash
	copy(priorState[:], r.GetPriorState().GetHash())

	var transA, transB *group.Transition
	if r.TransitionA != nil {
		ta, err := group.NewTransition(r.TransitionA, groupKey)
		if err != nil {
			return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("invalid transition_a: %w", err))
		}
		transA = ta
	}
	if r.TransitionB != nil {
		tb, err := group.NewTransition(r.TransitionB, groupKey)
		if err != nil {
			return nil, connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("invalid transition_b: %w", err))
		}
		transB = tb
	}

	state.StoreEvidence(&group.EquivocationEvidence{
		GroupID:      groupKey,
		StewardKey:   stewardKey,
		PriorState:   priorState,
		TransitionA:  transA,
		TransitionB:  transB,
	})

	return connect.NewResponse(&pb.Ack{
		Ok:     true,
		Detail: "evidence stored",
	}), nil
}

// lookup resolves a group public key to a *group.State. Returns
// (nil, NotFound) if this host does not serve that group.
func (s *Service) lookup(gid types.PublicKey) (*group.State, error) {
	st, ok := s.groups.Get(gid)
	if !ok {
		return nil, connect.NewError(connect.CodeNotFound, fmt.Errorf("group not hosted here"))
	}
	return st, nil
}

// Subscribe implements the server-streaming Subscribe RPC. It
// registers a channel on the group's Broadcaster and forwards
// events to the ConnectRPC server stream until the client context
// is cancelled.
//
// If since_index is non-zero, transitions already in the log with
// index > since_index are replayed before live streaming begins.
//
// (Audit C-5, cycle 51.)
func (s *Service) Subscribe(
	ctx context.Context,
	req *connect.Request[pb.SubscribeRequest],
	stream *connect.ServerStream[pb.TransitionEvent],
) error {
	r := req.Msg
	if r == nil {
		return connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("nil request"))
	}
	if r.GroupKey == nil {
		return connect.NewError(connect.CodeInvalidArgument, fmt.Errorf("group_key is nil"))
	}
	groupKey := bytesToKey(r.GroupKey.Raw)
	state, err := s.lookup(groupKey)
	if err != nil {
		return err
	}

	bc := state.Broadcaster()
	ch, unsub := bc.Subscribe()
	defer unsub()

	// Replay: if the client passed since_index, walk the log and
	// send any transitions with index > since_index before going live.
	// This gives crash-recovery semantics.
	sinceIndex := r.GetSinceIndex()
	if sinceIndex > 0 {
		log := state.Log()
		currentRoot := state.Root()
		for i := int(sinceIndex); i < len(log); i++ {
			if ctx.Err() != nil {
				return ctx.Err()
			}
			ev := pb.TransitionEvent{
				Transition: log[i].Proto,
				NewStateRoot: &pb.StateRoot{
					Hash: currentRoot[:],
				},
				TransitionIndex: uint64(i),
				GroupKey:        keyToProto(groupKey),
			}
			if err := stream.Send(&ev); err != nil {
				return err
			}
		}
	}

	// Live streaming: forward events from the broadcaster channel
	// to the ConnectRPC stream until the client disconnects.
	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case ev, ok := <-ch:
			if !ok {
				return nil
			}
			pbEv := pb.TransitionEvent{
				Transition: ev.Transition.Proto,
				NewStateRoot: &pb.StateRoot{
					Hash: ev.NewRoot[:],
				},
				TransitionIndex: ev.Index,
				GroupKey:        keyToProto(groupKey),
			}
			if err := stream.Send(&pbEv); err != nil {
				return err
			}
		}
	}
}

// ----- Type bridges --------------------------------------------------------

// bytesToKey converts a raw byte slice to a types.PublicKey. Returns the
// zero key if the slice is the wrong length.
func bytesToKey(b []byte) types.PublicKey {
	var k types.PublicKey
	copy(k[:], b)
	return k
}

// keyToProto converts a types.PublicKey to *pb.PublicKey.
func keyToProto(k types.PublicKey) *pb.PublicKey {
	return &pb.PublicKey{Raw: k[:]}
}

// stewardsToProto converts a slice of Steward to a slice of *pb.PublicKey.
func stewardsToProto(stewards []group.Steward) []*pb.PublicKey {
	out := make([]*pb.PublicKey, 0, len(stewards))
	for _, st := range stewards {
		out = append(out, keyToProto(st.Key))
	}
	return out
}

// stateSnapshotToProto converts a types.StateSnapshot to *pb.StateSnapshot.
//
// The root is passed separately because types.StateSnapshot does not embed
// its own root (it is computed from the entries on demand).
func stateSnapshotToProto(snap types.StateSnapshot, root types.Hash) *pb.StateSnapshot {
	entries := make([]*pb.StateEntry, 0, len(snap.Entries))
	for _, e := range snap.Entries {
		entries = append(entries, &pb.StateEntry{
			Key:   e.Key,
			Value: e.Value,
		})
	}
	return &pb.StateSnapshot{
		Root: &pb.StateRoot{
			Hash: root[:],
		},
		Entries: entries,
	}
}
